// // This module is designed to decrement a 3-bit binary counter on each positive edge of the clock signal and reset to 7 when the reset signal is high.
module up_counter_3bit(
    input clk,
    input reset,

    output reg [2:0] count
);

// Counter logic
always @(posedge clk or posedge reset)
begin
    if (reset)
        count <= 3'b000;
    else
        count <= count + 1;
end

endmodule
